<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;

class RisultatiController extends Controller
{
        public $risultati =[
        ['id'=>1,'titolo'=>'Cremonese vs Milan', 'risultato'=>'La partita è finita 0-2 a favore del Milan', 'img'=>'data:image/png;base64,'],
        ['id'=>2,'titolo'=>'Sassuolo vs Atalanta', 'risultato'=>'La partita è finita 2-1 a favore del Sassuolo', 'img'=>'data:image/png;base64,'],
        ['id'=>3,'titolo'=>'Torino vs Lazio', 'risultato'=>'La partita è finita 2-0 a favore del Torino', 'img'=>'data:image/png;base64,'],
        ['id'=>4,'titolo'=>'Roma vs Juventus', 'risultato'=>'La partita è finita 2-2', 'img'=>'data:image/png;base64,'],
    ];

    public function risultati(){
    return view('risultati.risultati',['risultati'=>$this->risultati]);
}

    public function listaRisultati($id){
    foreach($this->risultati as $risultato){
        if($id == $risultato['id']){
            return view('risultati.risultati-detail',['risultato'=>$risultato]);
        }
    }
}

}
